function solve(n) {
    // Function to reverse the digits of a number
    const reverseNumber = (num) => {
        return parseInt(String(num).split('').reverse().join(''));
    };

    // Calculate r
    const r = reverseNumber(n);

    // Determine the range [start, end]
    const start = Math.min(n, r);
    const end = Math.max(n, r);

    // Sieve of Eratosthenes to pre-calculate primes up to 'end'
    // Since n <= 1000, end <= 1000.
    const limit = end;
    const isPrime = new Array(limit + 1).fill(true);
    isPrime[0] = false;
    isPrime[1] = false;

    for (let p = 2; p * p <= limit; p++) {
        if (isPrime[p]) {
            for (let i = p * p; i <= limit; i += p)
                isPrime[i] = false;
        }
    }

    let sumOfPrimes = 0;

    // Sum all primes in the range [start, end]
    for (let i = start; i <= end; i++) {
        if (isPrime[i]) {
            sumOfPrimes += i;
        }
    }

    return sumOfPrimes;
}

